INSERT OR IGNORE INTO attribute(id, eid, key, name, description, game_id, version, created_by_sub, created_at, updated_at, deleted_at)
VALUES
  (1, 'c1000000-0000-0000-0000-000000000001', 'always_flying', 'Always Flying', 'This unit is always flying and cannot land.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (2, 'c1000000-0000-0000-0000-000000000002', 'armoured_vehicle', 'Armoured Vehicle', 'This unit has variable Missile Block Chance depending on which side of the unit is hit by a projectile. The missile block chance multiplier of each direction is: 1.0x at the front 0.5x at the sides 0.1x at the rear', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (3, 'c1000000-0000-0000-0000-000000000003', 'bound_fire_daemon', 'Bound Fire Daemon', 'Bound Fire Daemons cannot be routed, but they take damage when their Leadership is broken. Bound Fire Daemons also have: Physical Resistance Fire Resistance Fear and Terror Immunity Bound Fire Daemons are also Unbreakable whilst most of their hit points are remaining.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (4, 'c1000000-0000-0000-0000-000000000004', 'can_block_missiles_360', 'Can Block Missiles 360', 'This unit can block projectiles regardless of its facing.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (5, 'c1000000-0000-0000-0000-000000000005', 'cant_run', 'Cant Run', 'This unit cannot run and will only move at walking pace.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (6, 'c1000000-0000-0000-0000-000000000006', 'causes_fear', 'Causes Fear', 'This unit frightens all enemy units, reducing their leadership when nearby. It is also immune to fear. Fear penalties do not stack.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (7, 'c1000000-0000-0000-0000-000000000007', 'causes_terror', 'Causes Terror', 'This unit can cause terror, making its melee target rout for a short time. Units that cause terror are immune to terror and fear themselves.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (8, 'c1000000-0000-0000-0000-000000000008', 'charge_defense', 'Charge Defense', 'When bracing, this unit negates the charge bonus of any attacker.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (9, 'c1000000-0000-0000-0000-000000000009', 'charge_defense_vs_large', 'Charge Defense Vs Large', 'When bracing, this unit negates the charge bonus of any large attacker.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (10, 'c1000000-0000-0000-0000-00000000000a', 'charge_reflection', 'Charge Reflection', 'When bracing, this unit causes additional damage when attacking charging enemies.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (11, 'c1000000-0000-0000-0000-00000000000b', 'construct', 'Construct', 'Constructs cannot be routed, but take damage when their Leadership is broken. Constructs also have: Fear and Terror Immunity Constructs may also have their hit points restored and stats boosted by special characters such as the Tomb Kings Necrotect.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (12, 'c1000000-0000-0000-0000-00000000000c', 'contempt', 'Contempt', 'Witnessing other friendly units rout will only affect this unit''s leadership if they also have the Contempt attribute.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (13, 'c1000000-0000-0000-0000-00000000000d', 'daemonic', 'Daemonic', 'Daemonic units cannot be routed, but take damage when their Leadership is low. Daemonic units also have: Physical Resistance Fear and Terror Immunity', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (14, 'c1000000-0000-0000-0000-00000000000e', 'devastating_flanker', 'Devastating Flanker', 'Entities with this attribute double their charge bonus when attacking the rear or flank of an entity.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (15, 'c1000000-0000-0000-0000-00000000000f', 'elemental', 'Elemental', 'Elementals cannot be routed, but take damage when their Leadership is broken. Elementals also have: Physical Resistance Fear and Terror Immunity', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (16, 'c1000000-0000-0000-0000-000000000010', 'encourages', 'Encourages', 'This unit provides a leadership bonus to nearby allies. Units within range of both the Lord''s aura and an encouraging unit will receive the larger of the two bonuses.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (17, 'c1000000-0000-0000-0000-000000000011', 'expendable', 'Expendable', 'Witnessing friendly expendable units rout does not reduce other units'' leadership, unless they are themselves expendable.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (18, 'c1000000-0000-0000-0000-000000000012', 'fatigue_immune', 'Fatigue Immune', 'Even when performing the most fatiguing actions, this unit never loses vigour.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (19, 'c1000000-0000-0000-0000-000000000013', 'flanking_immune', 'Flanking Immune', 'This unit takes no penalties when flanked.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (20, 'c1000000-0000-0000-0000-000000000014', 'flying', 'Flying', 'This unit can fly.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (21, 'c1000000-0000-0000-0000-000000000015', 'formed_attack', 'Formed Attack', 'The unit will try to stay in formation when in melee. Melee defence will be slightly increased.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (22, 'c1000000-0000-0000-0000-000000000016', 'glorious_charge', 'Glorious Charge', 'When charging into an enemy unit: Charge Bonus duration is doubled. Enemy units take a Leadership penalty as if they have been attacked in the flank.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (23, 'c1000000-0000-0000-0000-000000000017', 'gorger', 'Gorger', 'This unit counts as a Gorger for ability targeting', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (24, 'c1000000-0000-0000-0000-000000000018', 'guerrilla_deploy', 'Guerrilla Deploy', 'This unit can deploy outside the deployment zone.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (25, 'c1000000-0000-0000-0000-000000000019', 'gunship', 'Gunship', 'This unit relies entirely on missile attacks to deal damage and has no melee capabilities. Gunship-type units also: Attack ground targets from directly above Attack flying targets from range Have certain riders with infinite Ammunition', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (26, 'c1000000-0000-0000-0000-00000000001a', 'hellforged', 'Hellforged', 'This unit can be restored in battle by the Daemonsmith''s Reforge ability.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (27, 'c1000000-0000-0000-0000-00000000001b', 'hide_forest', 'Hide Forest', 'This unit can hide in forests until enemy units get too close.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (28, 'c1000000-0000-0000-0000-00000000001c', 'ignore_imbue_contact_effects_enemy', 'Ignore Imbue Contact Effects Enemy', 'Entities with this attribute ignore the effects of enemy contact effects such as Poison', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (29, 'c1000000-0000-0000-0000-00000000001d', 'ignore_trees', 'Ignore Trees', 'This unit can pass through trees.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (30, 'c1000000-0000-0000-0000-00000000001e', 'immune_to_psychology', 'Immune To Psychology', 'The unit is immune to psychological attacks (Fear & Terror).', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (31, 'c1000000-0000-0000-0000-00000000001f', 'knight', 'Knight', 'Witnessing friendly units with the Peasant Attribute rout will not affect this unit''s leadership.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (32, 'c1000000-0000-0000-0000-000000000020', 'kroxigor', 'Kroxigor', 'A unit with the Kroxigor will gain the following bonuses if a unit with the Skink Attribute is nearby: Increased Weapon Strength', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (33, 'c1000000-0000-0000-0000-000000000021', 'mark_khorne', 'Mark Khorne', 'A unit with the Mark of Khorne has: Frenzy Passive Ability Increased Spell Resistance Increased Armour Reduced Melee Defence', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (34, 'c1000000-0000-0000-0000-000000000022', 'mark_nurgle', 'Mark Nurgle', 'A unit with the Mark of Nurgle has: Poison Contact Effect Increased Hit Points Increased Melee Defence Reduced Melee Attack', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (35, 'c1000000-0000-0000-0000-000000000023', 'mark_slaanesh', 'Mark Slaanesh', 'A unit with the Mark of Slaanesh has: Immune to Psychology Attribute Strider Attribute Increased Physical Resistance Increased Speed', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (36, 'c1000000-0000-0000-0000-000000000024', 'mark_tzeentch', 'Mark Tzeentch', 'A unit with the Mark of Tzeentch has: Barrier Magical Attacks', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (37, 'c1000000-0000-0000-0000-000000000025', 'moulder_monster', 'Moulder Monster', 'This is a unit created by Clan Moulder. Packmasters and Throt the Unclean can push it to its full combat potential and restore it in battle.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (38, 'c1000000-0000-0000-0000-000000000026', 'mounted_fire_move', 'Mounted Fire Move', 'This unit can fire while on the move.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (39, 'c1000000-0000-0000-0000-000000000027', 'ogre_charge', 'Ogre Charge', 'When attacking braced charge defenders, this unit only loses half of its charge bonus.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (40, 'c1000000-0000-0000-0000-000000000028', 'peasant', 'Peasant', 'A unit with the Peasant Attribute will gain increased leadership if a unit with the Knight Attribute is nearby.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (41, 'c1000000-0000-0000-0000-000000000029', 'rampage', 'Rampage', 'A Rampaging unit is uncontrollable and will attack the nearest enemy unit. When there are no enemy units nearby, a Rampaging unit will move around randomly instead.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (42, 'c1000000-0000-0000-0000-00000000002a', 'randomises_spells_on_cast', 'Randomises Spells On Cast', 'When this unit casts a spell, all of their spells will be randomly replaced by another spell.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (43, 'c1000000-0000-0000-0000-00000000002b', 'skink', 'Skink', 'A unit with the Skink Attribute will gain the following bonuses if a unit with the Kroxigor Attribute is nearby: Causes Fear', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (44, 'c1000000-0000-0000-0000-00000000002c', 'slayer', 'Slayer', 'This unit is a Slayer. Slayers can never have their Weapon Strength reduced during a battle.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (45, 'c1000000-0000-0000-0000-00000000002d', 'snipe', 'Snipe', 'This unit remains hidden while firing.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (46, 'c1000000-0000-0000-0000-00000000002e', 'spell_mastery', 'Spell Mastery', 'When two or more units in the same army share this attribute, intensity increases the power of spells cast.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (47, 'c1000000-0000-0000-0000-00000000002f', 'squig', 'Squig', 'This unit counts as a Squig for ability targeting', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (48, 'c1000000-0000-0000-0000-000000000030', 'stalk', 'Stalk', 'This unit can move hidden in any terrain.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (49, 'c1000000-0000-0000-0000-000000000031', 'strider', 'Strider', 'Speed and combat penalties caused by terrain are ignored by this unit.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (50, 'c1000000-0000-0000-0000-000000000032', 'unbreakable', 'Unbreakable', 'This unit does not suffer any form of leadership loss and will never rout.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (51, 'c1000000-0000-0000-0000-000000000033', 'undead', 'Undead', 'Undead units cannot be routed, but take damage when their {{tr:morale}} is broken. Undead units also have: Fear and Terror Immunity Undead units may also have their hit points restored by special characters such as the Vampire Counts Necromancer.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (52, 'c1000000-0000-0000-0000-000000000034', 'underground', 'Underground', 'The Dread Maw is underground. It cannot be attacked but neither can it attack in turn.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (53, 'c1000000-0000-0000-0000-000000000035', 'unspottable', 'Unspottable', 'If this unit can hide at its current location it will not be spotted until the enemy is very close.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (54, 'c1000000-0000-0000-0000-000000000036', 'unyielding_assault', 'Unyielding Assault', 'This unit can never have its Melee Attack reduced during battle.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (55, 'c1000000-0000-0000-0000-000000000037', 'wallbreaker', 'Wallbreaker', 'Allows the unit to attack and destroy walls in melee. This attribute also adds a +50% damage multiplier against buildings.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (56, 'c1000000-0000-0000-0000-000000000038', 'yang', 'Yang', 'This unit counts as a Yang unit for the purpose of Battle Harmony proximity', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (57, 'c1000000-0000-0000-0000-000000000039', 'yin', 'Yin', 'This unit counts as a Yin unit for the purpose of Battle Harmony proximity.', 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null);
